import{_ as b,o as a,c as e,j as r,a as t,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"闪刀姬","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/5.通用类/闪刀姬.md","filePath":"4.资源分区/2.改造与功法/改造/5.通用类/闪刀姬.md"}'),d={name:"4.资源分区/2.改造与功法/改造/5.通用类/闪刀姬.md"};function n(o,p,l,c,_,i){return a(),e("div",null,[...p[0]||(p[0]=[r("h1",{id:"闪刀姬",tabindex:"-1"},[t("闪刀姬 "),r("a",{class:"header-anchor",href:"#闪刀姬","aria-label":'Permalink to "闪刀姬"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风025春节版")])])],-1),s('<h1 id="闪刀姬-1" tabindex="-1">闪刀姬 <a class="header-anchor" href="#闪刀姬-1" aria-label="Permalink to &quot;闪刀姬&quot;">​</a></h1><p>改造-闪刀系统<br> &lt;祈愿祖国的和平，为此奔赴战场的少女的故事&gt;<br> 国家为对抗强大的军事帝国开发出了高端技术兵器「闪刀机」。而被授予了能操控「闪刀机」的钥匙“闪刀”的少女「零衣」，则为了守护国民而奔赴战场。</p><p>【闪刀武器】<br> D+600<br> 虽然看上去只是普通少女，但是凭借与生俱来的才能和所接受的特殊训练，「零衣」掌握了解放闪刀之力的方法。</p><p>购买此改造后，你获得一把用于释放术式的【闪刀】，类别为武士刀，体积3，具有【高速1】，武器伤害6L。</p><p>特别的，你也可以选择将一把你已有的刀类武器改造为你的【闪刀】，改为提升此武器3L武器伤害，攻击时额外获得1DP器械加值。<br> 当你提升此改造等级，或从影片回到幕间时，你可以更改你持有【闪刀】改造的武器。<br> 无论如何，你至多只能有一把武器获得【闪刀】改造。</p><p>每场影片过后，若你在这场影片中战胜了至少一个同级的敌人，则你的【闪刀】武器伤害提升1L。</p><p>当你购买此改造后，选定一项你已有的刀类武器专业，选定后不可更改，此后本资源内描述的【闪刀】检定，均为使用此武器专业的武技检定。</p><p>【闪刀空域-零区】<br> C+1200<br> 从小规模遭遇战到大兵团作战，各种各样的战斗在纷争区域的各地各处反复地上演着。「零衣」在接到了战斗开始的报告后，通过使用「闪刀机」开启了军事行动“闪略”。</p><p>【增援】<br> 为了应对世界各地的战乱，闪刀姬身上的装备配有远距离加速移动装置，<br> 经过十分钟的加速准备，闪刀姬能够以至多500km/h的速度进行移动，在一小时到一日内足以从大陆的一端来到另一端。<br> 加速移动过程中，默认失去所有动作，不可进入战斗轮（进入战斗则速度失效），这是一个C级时空来源的【旅行】效果。</p><p>【试胆竞速】<br> 闪刀姬的装备带有激发潜能的效果，但也会对使用者造成负荷<br> 每轮一次，你可以用自由动作对自身造成3点不可豁免的冲击点数，本轮中你获得使用【闪刀】检定的1点器械加值和2AP，<br> 以此方法获得的的AP仅能用于转化为使用【闪刀】下属能力的AP。</p><p>【哥布林暴发户】<br> 不知道为什么闪刀姬会和一群哥布林暴发户扯上关系，但这群哥布林的确是闪刀姬背后的金主，会根据闪刀姬的任务完成情况发放奖励<br> 在影片中，每当你击败1个至少同级的敌人（每高一级则多计一个），则你获得250分的报酬。<br> 当影片结束后，以此方法获得的报酬可以转化为等量的XP，仅能用于购买【闪刀】系列资源。<br> 每场影片中，你至多以此方法获得500分的报酬。</p><p>【闪刀机关-多任务战刀机】<br> B+2400<br> 凭借「零衣」稀世的才能，以往不可能实现的能进行大批量军备传送与操控的「多任务战刀机」系统完成了。</p><p>【战斗辅助系统】<br> 代替C级的【试胆竞速】效果，现在你每轮都可以获得额外的4点AP，仅能用于转化为使用【闪刀】技艺或奇物的动作<br> 并且你每购买过一种【闪刀】技艺或奇物（包括【闪刀启动】），就获得三豁免和【闪刀】检定上的【2】点器械加值，因此获得的加值最多等同于你【智力】的数值。</p><p>【折叠空间技术】<br> 【多任务战刀机】为你提供了随身的储物空间，具有1000立方米大小，在战斗外可以存入自愿或无助的生命体，取出和存放是一个花招动作，这是一个B级时空来源的【异空间】效果。该空间内的单位将处于无助状态。</p><p>【闪刀机构-大力神基地】<br> A+4800<br> 专门研发的军用机「大力神基地」，可以搭载诸多「闪刀机」提高「零衣」的作战效率。</p><p>【武装合体】<br> 你选择使用一个自由动作与军用机合体，使自身的体积增大【30】，但不会给你带来生命上限的提高，如同【虚拟体积】一样处理。你获得5点抵高速，在反射豁免上获得6DP器械加值；你以【闪刀】检定施展的攻击具有【余波】效果。</p><p>【连续攻击】<br> 每轮一次，当你施展【闪刀】技艺后，可以发动一次不包含任何技艺的【闪刀】攻击。</p><p>【生命回收】<br> 当你死亡时，大力神基地会将你的意识上传，并开启再生产指令。你需要提前在任意触及距离内的位置留下一个可以储存意识数据的标记，标记同时只能存在一个，只要标记存在，那么一周结束后你就可以复活。<br> 标记本身处于数据态，如同灵体一样存在，承载你死后的意识，你可以以标记为视角向外观察，或移动标记，标记本身具有等同你意志值的结构值，清空则标记损坏，需要你重新布置。若你处于复活期间，标记被破坏则复活失败。这是一个A级信息/时空来源的复活能力。<br> 理所当然的，这一标记需要你在进入影片后布置，提前在主神空间布置的标记毫无意义。</p><p>【闪刀】技艺（全部给技艺的成长性加了本场战斗内描述）：</p><p>【闪刀起动】<br> C+1000<br> 通过控制、装备从特殊出口发射出来的「闪刀机」，「零衣」就能变身为「闪刀姬」投身到纷争地区的战斗之中。<br> 另外，「闪刀姬」还存在能够分别应对各种战况的不同模式，装设在各个模式之中的奥义「闪刀术式」都拥有着能够一转战局的威力。</p><p>以一个整轮动作，你启动【闪刀】变身为以下四种【闪刀姬】形态之一，持续一个场景，你可以用一个整轮动作切换形态<br> 【连刀】：若在使用此技艺前，本场战斗中，你已经使用了【3】次其他的【闪刀】技艺，则本场景内你使用【闪刀】检定时获得【8加骰】（12dp）</p><p>【闪刀姬-燎里】<br> &lt;「极地特攻型闪灭模式」&gt;<br> 分作8片的“闪刀”展开炎翼，以其压倒性的火力使敌阵崩溃的歼灭型模式。</p><p>变身为此形态后，你的【闪刀】检定获得7L武器伤害提升</p><p>【闪刀姬-雫空】<br> &lt;「据点防卫型刀卫模式」&gt;<br> 生成从实弹到能量弹的各种攻击都能够抵御的障壁，以此防卫本军据点的模式。</p><p>变身为此形态后，你获得3点【全伤害吸收】</p><p>【闪刀姬-魁奈】<br> &lt;「近距格斗型斗闪模式」&gt;<br> 拥有4条巨大的格斗用装甲臂，专精于中近距离的格斗战，是继「燎里」之后的另一种攻击型模式。</p><p>变身为此形态后，你额外获得两体可用的机械臂肢体<br> 每轮一次，若你本轮使用过【闪刀】技艺或奇物，则你获得持续一轮的【快速医疗1：20医疗点】</p><p>【闪刀姬-飒天】<br> &lt;「侵攻迎击型击刀模式」&gt;<br> 专精于远距离作战的模式，通过巨大的电磁炮释放出的能量对敌方主力进行精确打击。</p><p>变身为此形态后，你使用【闪刀】检定进行的攻击射程提高20m</p><p>【闪刀术式-烈火再燃】<br> C+1000<br> 以一个标准动作，你使用【闪刀】检定进行攻击，此次攻击对以你为中心，半径为【闪刀】攻击射程的圆形范围内所有敌人造成伤害</p><p>【连刀】：若在使用此技艺前，本场战斗中，你已经使用了【3】次其他的【闪刀】技艺，<br> 则本次【闪刀】攻击检定附带等同于你【内在最高支线等级数】（即d1c2b3a4s5）点不可豁免的【燃烧】不良点数</p><p>【闪刀术式-妨害波纹】<br> C+1000<br> 以一个标准动作，你进行一次全力防御并额外获得等同于你【内在最高支线等级数】（即d1c2b3a4s5）点偏斜防御<br> 在你的回合外，针对一次你能认知到的攻击，你可以用一个反射动作调用下回合的标准动作施展此技艺</p><p>【连刀】：若在使用此技艺前，本场战斗中，你已经使用了【3】次其他的【闪刀】技艺，<br> 则本技艺还会额外提供仅持续一轮的【10】点临时生命<br> 并且施展本技艺时，你还可以选择为你触及范围内的友方成员提供【全遮蔽】效果</p><p>【闪刀术式-剪斗交刃】<br> C+1000<br> 以一个标准动作，你使用【闪刀】检定进行攻击，若在你攻击前你的肢体有缺损（包括额外获得的肢体），<br> 则此次攻击时，你的肢体立刻再生并恢复至全部完好的状态（包括头部）</p><p>【连刀】：若在使用此技艺前，本场战斗中，你已经使用了【3】次其他的【闪刀】技艺，<br> 则你的此次【闪刀】攻击检定视作具有【能量武器】，受到攻击的单位需要进行一次强韧豁免，失败则被施加【劣化1】，这是一个C级别、创伤来源的负面效果<br> 并且你进行攻击后视作额外进行了【格挡】</p><p>【闪刀术式-爆风偏向】<br> C+1000<br> 以一个标准动作，你使用【闪刀】检定进行攻击，此次攻击额外具有等同于你的【内在最高支线等级数*5】（即d5c10b15a20s25）的【高速】</p><p>【连刀】：若在使用此技艺前，本场战斗中，你已经使用了其他的【3】次【闪刀】技艺，<br> 则你的此次【闪刀】攻击检定视作具有【接触攻击】，【超级贯穿】效果</p><p>【闪刀】奇物：</p><p>【闪刀机-黑寡妇抓锚】<br> C+1000<br> 「零衣」可以通过装备「黑寡妇抓锚」来抓住敌军的兵装，还能用这种特殊装甲臂上放出的微弱电磁波使其失去作战能力。如果敌军的兵器是采用了自主武器系统的机械兵器，则还可以夺取其控制权。</p><p>你的【闪刀】攻击检定附带C级信息来源的【网络】和【思维控制】效果，<br> 针对命中的设备，以攻击检定出目对抗DC，若对抗成功，则可以通过无线信号骇入片区局域网、机密设备<br> 若命中的是具有心智的单位，对方以意志豁免对抗你的攻击检定出目，若你胜出，则你可以命令对方做出日常不会做，但是不挑战其基本价值观的事</p><p>【连刀】：若本场景中，你已经使用了【3】次【闪刀】技艺，<br> 则你额外获得等同于你的【内在最高支线等级数*3】（即d3c6b9a12s15）的【闪避防御】<br> 在你的回合外，针对一次你可以认识到的攻击，你可以用一个反射动作使用此奇物，进行一次打断性的移动，这会正常消耗你下回合的标准动作</p><p>【闪刀机-虎鲨加农炮】<br> C+1000<br> 「虎鲨加农炮」是在「零衣」的认知操作之下能够将弹着点毫无偏差地对准目标地点的超远距离武器。通过从敌方射程范围之外发出的攻击压制斯佩克特拉军队，让阵地的获取化为现实。</p><p>你在持有【闪刀】时具有【透视】效果<br> 你的【闪刀】攻击检定附带【免疫A级复活】效果，命中的目标无法以A级或以下的【复活】效果复活</p><p>【连刀】：若本场景中，你已经使用了【3】次【闪刀】技艺，<br> 则你的【闪刀】攻击检定将附带B级【重伤】效果，并且可以重骰一次，必须接受重骰的结果</p><p>【闪刀机-鹰式推进器】<br> C+1000<br> 与「闪刀系统」一同被开发出来的原始型推进器。具备能够控制功率输出方向的结构，使得士兵们能够按照自己心中所设想的轨道飞行。在这样的速度之下，「零衣」即便是在导弹等的超音速攻击中也能够保护自身。</p><p>购买后，你获得等同于你的移动速度的【普通】飞行速度，并且免疫【擒抱】状态</p><p>【连刀】：若本场景中，你已经使用了【3】次【闪刀】技艺，<br> 则你的飞行速度提升至【完美】，并且获得【免疫接触攻击】效果。以推进器进行冲锋攻击时，你的基础防御不会受到减值</p><p>【闪刀机-大黄蜂浮游单元】<br> C+1000<br> 从「闪刀机」中能够射出随「零衣」的意念自由飞行的小型机械「大黄蜂浮游单元」，它们能够代替「零衣」承受来自敌人的攻击，也能进行索敌和侦查来得到敌军配置等重要情报。</p><p>你获得一种C级特异本质来源的【侦测效果】<br> 此外，浮游单元还可以释放全息投影以迷惑敌人，你可以在你的敏感范围内召唤出任意数量的，外表和你相同的全息投影<br> 这些投影可以模拟你的动作，但不会行动，并且没有详细细节，无实体，这是一个C级幻象来源的【幻象】效果</p><p>【连刀】：若本场景中，你已经使用了【3】次【闪刀】技艺，<br> 当你的移动范围内存在全息影像时，你可以用一个移动动作瞬移至全息影像处，这是一个C级时空来源的【传送移动】效果<br> 不断生成的全息影像可以扰乱敌人的行动，而藏于影像中的浮游单元可以作为你行动的跳板<br> 你的触及范围内视作C级信息来源的【困难地形】，并且你免疫B级【困难地形】效果</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',52)])])}const f=b(d,[["render",n]]);export{h as __pageData,f as default};
